// client/src/components/Loading.js
import React from 'react';
import { PawIcon } from './Icons';

const Loading = () => {
  return (
    <div className="flex flex-col items-center justify-center h-screen bg-cat-light">
      <div className="animate-bounce">
        <PawIcon className="w-16 h-16 text-cat-primary" />
      </div>
      <p className="mt-4 text-xl font-bold text-cat-dark">Загрузка...</p>
      <p className="mt-2 text-cat-dark">Подготавливаем кошачье поселение</p>
    </div>
  );
};

export default Loading;
